/**
 * @name Stored XSS - Entity data in Vaadin HTML content mode labels
 * @description User-controlled entity names/descriptions used in Vaadin labels with ContentMode.HTML without HTML encoding
 * @kind path-problem
 * @problem.severity error
 * @id java/stored-xss-vaadin-html-label
 * @tags security
 *       external/cwe/cwe-079
 */

import java
import semmle.code.java.dataflow.TaintTracking
import semmle.code.java.dataflow.DataFlow

// Entity getter methods that return user-controlled strings
class EntityDataGetter extends MethodCall {
  EntityDataGetter() {
    (
      this.getMethod().hasName("getName") or
      this.getMethod().hasName("getDescription") or
      this.getMethod().hasName("getVersion") or
      this.getMethod().hasName("getFilename") or
      this.getMethod().hasName("getControllerId")
    )
    and
    // Called on objects from org.eclipse.hawkbit packages (entities)
    this.getMethod().getDeclaringType().getPackage().hasName("org.eclipse.hawkbit.repository.model")
    or
    (
      this.getMethod().hasName("getName") or
      this.getMethod().hasName("getDescription") or
      this.getMethod().hasName("getVersion") or
      this.getMethod().hasName("getFilename")
    )
    and this.getMethod().getDeclaringType().getPackage().getName().matches("org.eclipse.hawkbit%")
  }
}

// Vaadin Label.setCaption or Label.setValue when used with HTML content mode
class VaadinHtmlContentSink extends MethodCall {
  VaadinHtmlContentSink() {
    (
      this.getMethod().hasName("setCaption") or
      this.getMethod().hasName("setValue")
    )
    and this.getMethod().getDeclaringType().hasQualifiedName("com.vaadin.ui", "Label")
  }
}

// AbstractHtmlLabelConverter.convert() 
class HtmlLabelConverterSink extends MethodCall {
  HtmlLabelConverterSink() {
    this.getMethod().hasName("setDescription")
    and this.getMethod().getDeclaringType().getASupertype*().getPackage().hasName("com.vaadin.ui")
  }
}

module XssSinkConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    source.asExpr() instanceof EntityDataGetter
  }

  predicate isSink(DataFlow::Node sink) {
    // Vaadin setValue/setCaption on Label
    exists(VaadinHtmlContentSink vhs |
      sink.asExpr() = vhs.getArgument(0)
    )
    or
    // setDescription in Vaadin
    exists(HtmlLabelConverterSink hlcs |
      sink.asExpr() = hlcs.getArgument(0)
    )
    or
    // HTML append patterns in HawkbitCommonUtil and DistributionBarHelper
    exists(MethodCall mc |
      mc.getMethod().hasName("append") and
      sink.asExpr() = mc.getArgument(0) and
      mc.getEnclosingCallable().getDeclaringType().hasQualifiedName("org.eclipse.hawkbit.ui.utils", "HawkbitCommonUtil")
    )
    or
    exists(MethodCall mc |
      mc.getMethod().hasName("append") and
      sink.asExpr() = mc.getArgument(0) and
      mc.getEnclosingCallable().getDeclaringType().hasQualifiedName("org.eclipse.hawkbit.ui.rollout", "DistributionBarHelper")
    )
  }
}

module XssFlow = TaintTracking::Global<XssSinkConfig>;
import XssFlow::PathGraph

from XssFlow::PathNode source, XssFlow::PathNode sink
where XssFlow::flowPath(source, sink)
select sink.getNode(), source, sink,
  "Stored XSS: Entity data from $@ flows into HTML construction without encoding.",
  source.getNode(), "entity getter"

/**
 * @name Stored XSS in custom HTML renderers - unencoded entity data in grid cells
 * @description User-controlled data flows into custom HTML renderers (HtmlLabelRenderer, AbstractHtmlLabelConverter) without HTML encoding
 * @kind path-problem
 * @problem.severity error
 * @id java/stored-xss-html-renderer
 * @tags security
 *       external/cwe/cwe-079
 */

import java
import semmle.code.java.dataflow.TaintTracking
import semmle.code.java.dataflow.DataFlow

// Entity getters returning user-controlled strings
class EntityGetter extends MethodCall {
  EntityGetter() {
    (
      this.getMethod().hasName("getName") or
      this.getMethod().hasName("getDescription") or
      this.getMethod().hasName("getVersion") or
      this.getMethod().hasName("getFilename") or
      this.getMethod().hasName("getControllerId") or
      this.getMethod().hasName("getMessages")
    )
    and this.getMethod().getDeclaringType().getPackage().getName().matches("org.eclipse.hawkbit%")
  }
}

// AbstractHtmlLabelConverter.convert or setHTMLContentAllowed
class HtmlRendererSink extends MethodCall {
  HtmlRendererSink() {
    (
      // Vaadin column renderer setConverter 
      this.getMethod().hasName("setConverter") or
      // Setting HTML content in label
      this.getMethod().hasName("setHTMLContentAllowed") or
      // convert method in AbstractHtmlLabelConverter  
      (this.getMethod().hasName("convert") and
       this.getMethod().getDeclaringType().getASupertype*().hasQualifiedName("org.eclipse.hawkbit.ui.customrenderers.renderers", "AbstractHtmlLabelConverter"))
    )
  }
}

// Methods that return HTML strings used by renderers
class HtmlStringReturn extends MethodCall {
  HtmlStringReturn() {
    (
      this.getMethod().getDeclaringType().hasQualifiedName("org.eclipse.hawkbit.ui.utils", "HawkbitCommonUtil") or
      this.getMethod().getDeclaringType().hasQualifiedName("org.eclipse.hawkbit.ui.rollout", "DistributionBarHelper") or
      this.getMethod().getDeclaringType().hasQualifiedName("org.eclipse.hawkbit.ui.rollout", "StatusFontIcon")
    )
    and (
      this.getMethod().hasName("getStatusFontIcon") or
      this.getMethod().hasName("getDistributionBarAsHTMLString") or
      this.getMethod().hasName("getFormatedLabel") or 
      this.getMethod().hasName("getFormatedName") or
      this.getMethod().hasName("concatStrings") or
      this.getMethod().hasName("getNameVersion") or
      this.getMethod().hasName("getText")
    )
  }
}

module HtmlRendererConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    source.asExpr() instanceof EntityGetter
  }

  predicate isSink(DataFlow::Node sink) {
    // Data flowing into HTML string builders that produce HTML content
    exists(MethodCall mc |
      mc instanceof HtmlStringReturn and
      sink.asExpr() = mc.getAnArgument()
    )
    or
    // Vaadin Table.setItem or addItem with HTML content in cells
    exists(MethodCall mc |
      (mc.getMethod().hasName("addItem") or mc.getMethod().hasName("setColumnHeader")) and
      sink.asExpr() = mc.getAnArgument()
    )
  }
}

module HtmlRendererFlow = TaintTracking::Global<HtmlRendererConfig>;
import HtmlRendererFlow::PathGraph

from HtmlRendererFlow::PathNode source, HtmlRendererFlow::PathNode sink
where HtmlRendererFlow::flowPath(source, sink)
select sink.getNode(), source, sink,
  "Stored XSS: User entity data from $@ flows into HTML renderer without encoding.",
  source.getNode(), "entity getter"

/**
 * @name Stored XSS in filter button tooltips with entity tag/type names
 * @description Tag names or type names from database used in Vaadin button HTML tooltip without encoding
 * @kind path-problem
 * @problem.severity error
 * @id java/stored-xss-filter-button-tooltip
 * @tags security
 *       external/cwe/cwe-079
 */

import java
import semmle.code.java.dataflow.TaintTracking
import semmle.code.java.dataflow.DataFlow

// Entity getter for tag/type names
class TagNameGetter extends MethodCall {
  TagNameGetter() {
    this.getMethod().hasName("getName") and
    this.getMethod().getDeclaringType().getPackage().getName().matches("org.eclipse.hawkbit%")
  }
}

module FilterButtonConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    source.asExpr() instanceof TagNameGetter
  }

  predicate isSink(DataFlow::Node sink) {
    // HTML append in AbstractFilterButtons tooltip generation
    exists(MethodCall mc |
      mc.getMethod().hasName("append") and
      mc.getEnclosingCallable().getDeclaringType().getASupertype*().hasQualifiedName("org.eclipse.hawkbit.ui.common.filterlayout", "AbstractFilterButtons") and
      sink.asExpr() = mc.getArgument(0)
    )
    or
    // setDescription on Vaadin button - renders as HTML tooltip
    exists(MethodCall mc |
      mc.getMethod().hasName("setDescription") and
      mc.getMethod().getDeclaringType().getASupertype*().getPackage().hasName("com.vaadin.ui") and
      sink.asExpr() = mc.getArgument(0)
    )
  }
}

module FilterButtonFlow = TaintTracking::Global<FilterButtonConfig>;
import FilterButtonFlow::PathGraph

from FilterButtonFlow::PathNode source, FilterButtonFlow::PathNode sink
where FilterButtonFlow::flowPath(source, sink)
select sink.getNode(), source, sink,
  "Stored XSS: Tag/type name from $@ flows into HTML tooltip without encoding in filter button.",
  source.getNode(), "getName() on entity"

/**
 * @name Stored XSS via device action messages in action status grid
 * @description IoT device-reported status messages rendered in HTML grid without encoding
 * @kind path-problem
 * @problem.severity error
 * @id java/stored-xss-action-status-messages
 * @tags security
 *       external/cwe/cwe-079
 */

import java
import semmle.code.java.dataflow.TaintTracking
import semmle.code.java.dataflow.DataFlow

// Action status messages reported by IoT devices
class ActionMessageSource extends MethodCall {
  ActionMessageSource() {
    (
      this.getMethod().hasName("getMessages") and
      this.getMethod().getDeclaringType().getPackage().getName().matches("org.eclipse.hawkbit%")
    )
    or
    (
      this.getMethod().hasName("getMessage") and
      this.getMethod().getDeclaringType().getPackage().getName().matches("org.eclipse.hawkbit%")
    )
  }
}

module ActionMsgConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    source.asExpr() instanceof ActionMessageSource
  }

  predicate isSink(DataFlow::Node sink) {
    // setValue/setCaption calls in action history management UI
    exists(MethodCall mc |
      (mc.getMethod().hasName("setValue") or
       mc.getMethod().hasName("setCaption") or
       mc.getMethod().hasName("setDescription") or
       mc.getMethod().hasName("addItem") or
       mc.getMethod().hasName("setItem")) and
      mc.getEnclosingCallable().getDeclaringType().getPackage().getName()
        .matches("org.eclipse.hawkbit.ui.management.actionhistory%") and
      sink.asExpr() = mc.getAnArgument()
    )
    or
    // Append calls in HawkbitCommonUtil for HTML label building
    exists(MethodCall mc |
      mc.getMethod().hasName("append") and
      mc.getEnclosingCallable().getDeclaringType().hasQualifiedName(
        "org.eclipse.hawkbit.ui.utils", "HawkbitCommonUtil") and
      sink.asExpr() = mc.getArgument(0)
    )
  }
}

module ActionMsgFlow = TaintTracking::Global<ActionMsgConfig>;
import ActionMsgFlow::PathGraph

from ActionMsgFlow::PathNode source, ActionMsgFlow::PathNode sink
where ActionMsgFlow::flowPath(source, sink)
select sink.getNode(), source, sink,
  "Stored XSS: IoT device message from $@ flows into HTML output without encoding.",
  source.getNode(), "device action message"
